void main() {
  final hoje = DateTime(2026, 7, 22);
  final show = DateTime(2026, 9, 5, 20, 30);

  final restante = show.difference(hoje);
  final dias = restante.inDays;
  final semanas = dias ~/ 7;
  final resto = dias % 7;

  print('=== Contagem Regressiva ===');
  print('Evento: Show de Rock');
  print('Data: ${show.day}/${show.month}/${show.year} - ${show.hour}h${show.minute}');
  print('Faltam $dias dias para o show');
  print('Ou seja: $semanas semanas e $resto dias');
}

void main() {
  const pessoas = 4;
  const gorjetaPct = 10;
  final conta = 187.50;

  final gorjeta = conta * gorjetaPct / 100;
  final total = conta + gorjeta;
  final porPessoa = total / pessoas;
  final salgado = porPessoa > 50;

  print('=== Rachar a Conta ===');
  print('Mesa de $pessoas pessoas');
  print('Conta: R\$ ${conta.toStringAsFixed(2)}');
  print('Gorjeta ($gorjetaPct%): R\$ ${gorjeta.toStringAsFixed(2)}');
  print('Total: R\$ ${total.toStringAsFixed(2)}');
  print('Cada um paga: R\$ ${porPessoa.toStringAsFixed(2)}');
  print(salgado ? 'Veredito: saiu salgado!' : 'Veredito: tranquilo!');
}

