(int, int) analisar(int inicio) {
  int atual = inicio;
  int passos = 0;
  int pico = inicio;
  while (atual != 1) {
    atual = atual % 2 == 0 ? atual ~/ 2 : 3 * atual + 1;
    passos++;
    if (atual > pico) pico = atual;
  }
  return (passos, pico);
}

void main() {
  final numeros = [6, 7, 11, 27];
  print('=== Sequencia de Collatz ===');
  int campeao = 0;
  int recorde = 0;
  for (final inicio in numeros) {
    final (passos, pico) = analisar(inicio);
    print('$inicio -> $passos passos, pico $pico');
    if (passos > recorde) {
      recorde = passos;
      campeao = inicio;
    }
  }
  print('Campeao: $campeao com $recorde passos');
}

int mover(int n, String de, String para, String apoio) {
  if (n == 1) {
    print('Disco 1: $de -> $para');
    return 1;
  }
  final antes = mover(n - 1, de, apoio, para);
  print('Disco $n: $de -> $para');
  final depois = mover(n - 1, apoio, para, de);
  return antes + 1 + depois;
}

void main() {
  const discos = 3;
  print('=== Torre de Hanoi com $discos discos ===');
  final total = mover(discos, 'A', 'C', 'B');
  print('Total de movimentos: $total');
}

