projetos.cod:
void main() {
  final itens = <({String nome, double preco, int qtd})>[
    (nome: 'Arroz', preco: 5.50, qtd: 2),
    (nome: 'Feijao', preco: 8.00, qtd: 1),
    (nome: 'Cafe', preco: 12.90, qtd: 3),
    (nome: 'Pao', preco: 0.75, qtd: 10),
  ];

  final comSubtotal = itens
      .map((i) => (nome: i.nome, subtotal: i.preco * i.qtd))
      .toList();
  comSubtotal.sort((a, b) => b.subtotal.compareTo(a.subtotal));

  print('=== Carrinho de Compras ===');
  for (final item in comSubtotal) {
    print('${item.nome}: R\$ ${item.subtotal.toStringAsFixed(2)}');
  }

  final total = itens.fold<double>(0, (soma, i) => soma + i.preco * i.qtd);
  print('---------------------------');
  print('Total: R\$ ${total.toStringAsFixed(2)}');

  final caros = comSubtotal
      .where((i) => i.subtotal > 10)
      .map((i) => i.nome)
      .toList();
  print('Itens acima de R\$ 10: ${caros.join(', ')}');
}

void main() {
  const texto =
      'o gato subiu no telhado o outro gato tambem subiu '
      'e o cachorro latiu para o gato no telhado';

  final palavras = texto.split(' ');

  final contagem = <String, int>{};
  for (final p in palavras) {
    contagem.update(p, (n) => n + 1, ifAbsent: () => 1);
  }

  final ranking = contagem.entries.toList()
    ..sort((a, b) {
      final porQtd = b.value.compareTo(a.value);
      return porQtd != 0 ? porQtd : a.key.compareTo(b.key);
    });

  print('Total de palavras: ${palavras.length}');
  print('Palavras distintas: ${contagem.length}');
  print('--- Mais frequentes ---');
  for (final e in ranking.take(3)) {
    print('${e.key}: ${e.value}');
  }
}

void main() {
  final habilidades = <String, Set<String>>{
    'Ana': {'Dart', 'Flutter', 'Git'},
    'Bruno': {'Dart', 'SQL', 'Git'},
    'Carla': {'Python', 'SQL', 'Dart'},
  };

  final todas = <String>{};
  for (final skills in habilidades.values) {
    todas.addAll(skills);
  }

  var comuns = habilidades.values.first;
  for (final skills in habilidades.values) {
    comuns = comuns.intersection(skills);
  }

  print('Habilidades da equipe (${todas.length}):');
  print((todas.toList()..sort()).join(', '));
  print('Todos sabem: ${(comuns.toList()..sort()).join(', ')}');

  print('--- Por pessoa ---');
  final nomes = habilidades.keys.toList()..sort();
  for (final nome in nomes) {
    print('$nome sabe ${habilidades[nome]!.length} habilidades');
  }
}

