enum TipoConta { corrente, poupanca }

class Conta {
  final String titular;
  final TipoConta tipo;
  double _saldo;

  Conta(this.titular, this.tipo, this._saldo);

  double get saldo => _saldo;

  void depositar(double valor) {
    _saldo += valor;
    print('$titular depositou ${valor.toStringAsFixed(2)}.');
  }

  bool sacar(double valor) {
    if (valor > _saldo) {
      print('Saque de ${valor.toStringAsFixed(2)} negado.');
      return false;
    }
    _saldo -= valor;
    print('$titular sacou ${valor.toStringAsFixed(2)}.');
    return true;
  }

  @override
  String toString() =>
      'Conta ${tipo.name} de $titular: ${_saldo.toStringAsFixed(2)}';
}

void main() {
  final conta = Conta('Ana', TipoConta.corrente, 100);
  print(conta);
  conta.depositar(50);
  conta.sacar(30);
  conta.sacar(200);
  print('Saldo de ${conta.titular}: ${conta.saldo.toStringAsFixed(2)}');
}

enum Elemento { fogo, gelo }

class Personagem {
  final String nome;
  int _vida;

  Personagem(this.nome, this._vida);
  int get vida => _vida;
  set vida(int valor) => _vida = valor < 0 ? 0 : valor;

  void receberDano(int dano) {
    vida = _vida - dano;
    print('$nome ficou com $_vida de vida.');
  }

  @override
  String toString() => '$nome ($_vida de vida)';
}

class Mago extends Personagem {
  final Elemento elemento;

  Mago(String nome, this.elemento) : super(nome, 90);
  void conjurar(Personagem alvo) {
    final dano = elemento == Elemento.fogo ? 40 : 25;
    print('$nome conjura ${elemento.name}!');
    alvo.receberDano(dano);
  }
}

void main() {
  final vilao = Personagem('Ogro', 30);
  final mago = Mago('Aria', Elemento.fogo);
  print(mago);
  print(vilao);
  mago.conjurar(vilao);
  mago.conjurar(vilao);
  print(vilao);
}

enum Categoria { alimento, limpeza, bebida }

class Produto {
  final String nome;
  final double preco;
  final Categoria categoria;

  Produto(this.nome, this.preco, this.categoria);
}

class Carrinho {
  final String cliente;
  final List<Produto> itens = [];

  Carrinho(this.cliente);

  double get total => itens.fold(0.0, (soma, item) => soma + item.preco);

  void adicionar(Produto produto) {
    itens.add(produto);
    print('${produto.nome} adicionado (${produto.categoria.name}).');
  }

  void resumo() {
    print('Carrinho de $cliente: ${itens.length} itens.');
    print('Total: ${total.toStringAsFixed(2)}');
  }
}

void main() {
  final carrinho = Carrinho('Bruno');
  carrinho.adicionar(Produto('Arroz', 22.5, Categoria.alimento));
  carrinho.adicionar(Produto('Sabao', 8.0, Categoria.limpeza));
  carrinho.adicionar(Produto('Suco', 6.75, Categoria.bebida));
  carrinho.resumo();
}

