Future<void> baixar(String arquivo, int mb) async {
  print('Iniciando download de $arquivo ($mb MB)');
  for (var pct = 25; pct <= 100; pct += 25) {
    await Future.delayed(Duration(milliseconds: 150));
    print('  $arquivo: $pct por cento');
  }
  print('Concluido: $arquivo');
}

Future<void> main() async {
  final fila = {'musica.mp3': 8, 'album.zip': 40, 'capa.png': 2};
  print('Fila de downloads: ${fila.length} arquivos');
  var total = 0;
  for (final nome in fila.keys) {
    final tamanho = fila[nome]!;
    await baixar(nome, tamanho);
    total += tamanho;
  }
  print('Tudo pronto. Baixados $total MB no total.');
}

import 'dart:convert';

void main() {
  const texto = '''
  {
    "cidade": "Recife",
    "alunos": [
      {"nome": "Ana", "nota": 8.5},
      {"nome": "Bruno", "nota": 6.0},
      {"nome": "Clara", "nota": 9.5}
    ]
  }
  ''';
  final dados = jsonDecode(texto) as Map<String, dynamic>;
  final alunos = dados['alunos'] as List;
  print('Turma de ${dados['cidade']}: ${alunos.length} alunos');
  var soma = 0.0;
  for (final aluno in alunos) {
    final nota = (aluno['nota'] as num).toDouble();
    final situacao = nota >= 7 ? 'aprovado' : 'recuperacao';
    print('  ${aluno['nome']}: $nota ($situacao)');
    soma += nota;
  }
  final media = soma / alunos.length;
  print('Media da turma: ${media.toStringAsFixed(2)}');
}

import 'dart:math';

double raizSegura(double x) {
  if (x < 0) {
    throw ArgumentError('sem raiz real de $x');
  }
  return sqrt(x);
}

void main() {
  final entradas = [16.0, 2.0, -9.0, 81.0];
  print('Calculadora de raizes');
  for (final valor in entradas) {
    try {
      final r = raizSegura(valor);
      print('  raiz de $valor = ${r.toStringAsFixed(3)}');
    } on ArgumentError catch (e) {
      print('  erro: ${e.message}');
    }
  }
  final numeros = [4, 9, 15, 8, 16];
  print('Maior valor: ${numeros.reduce((a, b) => max(a, b))}');
  print('Menor valor: ${numeros.reduce((a, b) => min(a, b))}');
  print('2 elevado a 10 = ${pow(2, 10)}');
}

