int buscaBinaria(List<int> l, int alvo) {
  var lo = 0, hi = l.length - 1;
  while (lo <= hi) {
    var m = (lo + hi) ~/ 2;
    if (l[m] == alvo) return m;
    if (l[m] < alvo) {
      lo = m + 1;
    } else {
      hi = m - 1;
    }
  }
  return -1;
}

List<int> inverte(List<int> l) {
  var r = <int>[];
