int buscaBinaria(List<int> v, int alvo) {
  var lo = 0, hi = v.length - 1;
  while (lo <= hi) {
    var meio = (lo + hi) ~/ 2;
    if (v[meio] == alvo) return meio;
    if (v[meio] < alvo) lo = meio + 1; // descarta a esquerda
    else hi = meio - 1;              // descarta a direita
  }
  return -1;
}

