class Candidato {
  final String nome;
  int votos = 0;
  Candidato(this.nome);
}

void main() {
  final candidatos = {
    'A': Candidato('Ana'),
    'B': Candidato('Bruno'),
    'C': Candidato('Carla'),
  };
  final urna = ['A', 'B', 'A', 'C', 'B', 'A', 'X', 'C', 'B', 'A'];

  var brancos = 0;
  for (final voto in urna) {
    final c = candidatos[voto];
    if (c == null) {
      brancos++;
    } else {
      c.votos++;
    }
  }

  final total = urna.length;
  print('Apuracao de $total votos:');
  final ranking = candidatos.values.toList()
    ..sort((a, b) => b.votos.compareTo(a.votos));
  for (final c in ranking) {
    final pct = (c.votos * 100 / total).toStringAsFixed(1);
    print('${c.nome}: ${c.votos} votos ($pct%)');
  }
  print('Brancos/nulos: $brancos');
  print('Vencedor: ${ranking.first.nome}');
}

class Forca {
  final String palavra;
  final Set<String> acertadas = {};
  int erros = 0;
  Forca(this.palavra);

  bool tentar(String letra) {
    if (palavra.contains(letra)) {
      acertadas.add(letra);
      return true;
    }
    erros++;
    return false;
  }

  String get visivel =>
      palavra.split('').map((c) => acertadas.contains(c) ? c : '_').join(' ');

  bool get completou => palavra.split('').toSet().every(acertadas.contains);
}

void main() {
  final jogo = Forca('BANANA');
  const tentativas = ['A', 'E', 'B', 'O', 'N'];
  const maxErros = 6;

  for (final letra in tentativas) {
    final estado = jogo.tentar(letra) ? 'acertou' : 'errou';
    print('$letra -> $estado | ${jogo.visivel} | erros: ${jogo.erros}/$maxErros');
    if (jogo.completou) break;
  }

  final venceu = jogo.completou && jogo.erros < maxErros;
  print(venceu ? 'Voce venceu! A palavra era ${jogo.palavra}.' : 'Fim de jogo.');
}

class Calculadora {
  final List<double> pilha = [];

  void processar(String token) {
    final numero = double.tryParse(token);
    if (numero != null) {
      pilha.add(numero);
      return;
    }
    final b = pilha.removeLast();
    final a = pilha.removeLast();
    switch (token) {
      case '+':
        pilha.add(a + b);
      case '-':
        pilha.add(a - b);
      case '*':
        pilha.add(a * b);
      case '/':
        pilha.add(a / b);
    }
  }
}

void main() {
  final expr = '3 4 + 5 * 2 -';
  final calc = Calculadora();
  print('Expressao RPN: $expr');
  for (final token in expr.split(' ')) {
    calc.processar(token);
    print('  $token -> pilha: ${calc.pilha}');
  }
  print('Resultado: ${calc.pilha.single}');
}

