void main() {
  final tarefas = <({String titulo, int prioridade, bool feita})>[
    (titulo: 'Estudar Dart', prioridade: 1, feita: false),
    (titulo: 'Lavar louça', prioridade: 3, feita: true),
    (titulo: 'Revisar PR', prioridade: 1, feita: false),
    (titulo: 'Comprar pão', prioridade: 2, feita: false),
    (titulo: 'Escrever testes', prioridade: 2, feita: true),
  ];

  final pendentes = tarefas.where((t) => !t.feita).toList()
    ..sort((a, b) => a.prioridade.compareTo(b.prioridade));

  print('=== Tarefas pendentes (por prioridade) ===');
  for (final t in pendentes) {
    final rotulo = switch (t.prioridade) {
      1 => 'Alta',
      2 => 'Média',
      _ => 'Baixa',
    };
    print('[$rotulo] ${t.titulo}');
  }

  final concluidas = tarefas.where((t) => t.feita).length;
  print('---');
  print('Total: ${tarefas.length} | Pendentes: ${pendentes.length} | '
      'Concluídas: $concluidas');
}

sealed class EstadoPedido {}

class Criado extends EstadoPedido {}

class Pago extends EstadoPedido {}

class Enviado extends EstadoPedido {}

class Entregue extends EstadoPedido {}

class Cancelado extends EstadoPedido {}

String nomeDe(EstadoPedido e) => switch (e) {
      Criado() => 'Criado',
      Pago() => 'Pago',
      Enviado() => 'Enviado',
      Entregue() => 'Entregue',
      Cancelado() => 'Cancelado',
    };

EstadoPedido transicionar(EstadoPedido atual, String acao) {
  return switch ((atual, acao)) {
    (Criado(), 'pagar') => Pago(),
    (Criado(), 'cancelar') => Cancelado(),
    (Pago(), 'enviar') => Enviado(),
    (Pago(), 'cancelar') => Cancelado(),
    (Enviado(), 'entregar') => Entregue(),
    _ => throw StateError('${nomeDe(atual)} não aceita a ação "$acao"'),
  };
}

void main() {
  EstadoPedido estado = Criado();
  final acoes = ['pagar', 'enviar', 'entregar', 'cancelar'];

  print('Estado inicial: ${nomeDe(estado)}');
  for (final acao in acoes) {
    try {
      estado = transicionar(estado, acao);
      print('Ação "$acao" -> ${nomeDe(estado)}');
    } on StateError catch (e) {
      print('Ação "$acao" rejeitada: ${e.message}');
    }
  }
}

