Future<String> processarPedido(String pedido, Duration tempo) async {
  await Future.delayed(tempo);
  return 'Pedido "$pedido" pronto';
}

void main() async {
  final pedidos = <(String nome, Duration tempo)>[
    ('Pizza', Duration(milliseconds: 30)),
    ('Suco', Duration(milliseconds: 10)),
    ('Sobremesa', Duration(milliseconds: 20)),
  ];

  print('Fila com ${pedidos.length} pedidos recebida.');
  for (final (nome, _) in pedidos) {
    print('Iniciando: $nome');
  }

  final futuros = [
    for (final (nome, tempo) in pedidos) processarPedido(nome, tempo),
  ];

  final resultados = await Future.wait(futuros);

  print('--- Resultados (na ordem da fila) ---');
  for (final r in resultados) {
    print(r);
  }
  print('Todos os ${resultados.length} pedidos foram concluídos.');
}

