sealed class Resultado {}
class Ok extends Resultado { final Produto valor; Ok(this.valor); }
class Erro extends Resultado { final String mensagem; Erro(this.mensagem); }

class Produto {
  final String nome;
  int quantidade;
  Produto(this.nome, this.quantidade);
  @override
  String toString() => '$nome ($quantidade un.)';
}

class Estoque {
  final _produtos = <String, Produto>{};
  Resultado adicionar(String nome, int qtd) {
    final p = _produtos.putIfAbsent(nome, () => Produto(nome, 0));
    p.quantidade += qtd;
    return Ok(p);
  }
  Resultado baixar(String nome, int qtd) {
    final p = _produtos[nome];
    if (p == null) return Erro('produto "$nome" não encontrado');
    if (p.quantidade < qtd) return Erro('estoque insuficiente de "$nome"');
    p.quantidade -= qtd;
    return Ok(p);
  }
}

void relatar(String op, Resultado r) {
  switch (r) {
    case Ok(valor: final p):
      print('$op OK -> $p');
    case Erro(mensagem: final m):
      print('$op FALHOU -> $m');
  }
}

void main() {
  final estoque = Estoque();
  relatar('Adicionar Teclado', estoque.adicionar('Teclado', 10));
  relatar('Adicionar Mouse', estoque.adicionar('Mouse', 5));
  relatar('Baixar Teclado', estoque.baixar('Teclado', 3));
  relatar('Baixar Monitor', estoque.baixar('Monitor', 1));
  relatar('Baixar Mouse', estoque.baixar('Mouse', 10));
}

