class TabelaConversao {
  final _linhas = <String>[];

  void linha(String texto) => _linhas.add(texto);

  void imprimir() => _linhas.forEach(print);
}

void main() {
  final celsius = [0.0, 20.0, 37.0, 100.0];
  final tabela = TabelaConversao();

  tabela.linha('--- Temperaturas (C -> F) ---');
  for (final c in celsius) {
    final f = c.paraFahrenheit;
    tabela.linha('${c.toStringAsFixed(0)}C -> ${f.toStringAsFixed(1)}F');
  }

  final distancias = [5.0, 10.0, 42.0].where((km) => km > 0);
  tabela.linha('--- Distâncias (km -> milhas) ---');
  for (final km in distancias) {
    final mi = km.kmParaMilhas;
    tabela.linha('${km.toStringAsFixed(0)}km -> ${mi.toStringAsFixed(2)}mi');
  }

  tabela
    ..linha('--- Fim ---')
    ..imprimir();
}

