double descontoPara(TipoCliente tipo) => switch (tipo) {
      Normal() => 0.0,
      Vip() => 0.10,
      Fundador() => 0.20,
    };

String emReais(double valor) => 'R\$ ${valor.toStringAsFixed(2)}';

void main() {
  final carrinho = <({String nome, double preco, int quantidade})>[
    (nome: 'Teclado', preco: 150.0, quantidade: 1),
    (nome: 'Mouse', preco: 60.0, quantidade: 2),
    (nome: 'Monitor', preco: 899.9, quantidade: 1),
  ];

  final subtotal = carrinho.fold<double>(
    0,
    (soma, item) => soma + item.preco * item.quantidade,
  );

  final cliente = Vip();
  final desconto = descontoPara(cliente);
  final total = subtotal * (1 - desconto);

  print('=== Carrinho ===');
  for (final item in carrinho) {
    final linha = emReais(item.preco * item.quantidade);
    print('${item.quantidade}x ${item.nome}: $linha');
  }
  print('Subtotal: ${emReais(subtotal)}');
  print('Desconto (${(desconto * 100).toStringAsFixed(0)}%): '
      '${emReais(subtotal * desconto)}');
  print('Total: ${emReais(total)}');
}

