  final jogos = <(String mandante, String visitante, int golsM, int golsV)>[
    ('Leões', 'Tigres', 2, 1),
    ('Tigres', 'Águias', 0, 0),
    ('Águias', 'Leões', 1, 3),
    ('Leões', 'Águias', 2, 2),
    ('Tigres', 'Leões', 1, 0),
    ('Águias', 'Tigres', 2, 1),
  ];

  final pontos = <String, int>{};

  void somar(String time, int p) => pontos[time] = (pontos[time] ?? 0) + p;

  for (final (mandante, visitante, golsM, golsV) in jogos) {
    switch (golsM.compareTo(golsV)) {
      case > 0:
        somar(mandante, 3);
        break;
      case < 0:
        somar(visitante, 3);
        break;
      default:
        somar(mandante, 1);
        somar(visitante, 1);
        break;
    }
  }

  final classificacao = pontos.entries.toList()
    ..sort((a, b) => b.value.compareTo(a.value));

  print('=== Classificação ===');
  for (var i = 0; i < classificacao.length; i++) {
    final time = classificacao[i];
    print('${i + 1}º ${time.key} - ${time.value} pts');
  }
}

