class CampoInvalido implements Exception {
  final String campo;
  final String motivo;
  const CampoInvalido(this.campo, this.motivo);
  @override
  String toString() => '$campo: $motivo';
}

List<String> validar(String nome, int idade, String email) {
  final erros = <String>[];
  try {
    if (nome.trim().isEmpty) throw CampoInvalido('nome', 'vazio');
  } on CampoInvalido catch (e) {
    erros.add('$e');
  }
  try {
    if (idade < 0 || idade > 130) throw CampoInvalido('idade', 'inválida');
  } on CampoInvalido catch (e) {
    erros.add('$e');
  }
  try {
    if (!email.contains('@') || !email.contains('.')) throw CampoInvalido('email', 'inválido');
  } on CampoInvalido catch (e) {
    erros.add('$e');
  }
  return erros;
}

void main() {
  final formularios = <({String nome, int idade, String email})>[
    (nome: 'Ana Silva', idade: 30, email: 'ana@exemplo.com'),
    (nome: '', idade: 200, email: 'sememailarroba'),
  ];
  for (var i = 0; i < formularios.length; i++) {
    final f = formularios[i];
    final erros = validar(f.nome, f.idade, f.email);
    print('--- Formulário ${i + 1} ---');
    if (erros.isEmpty) {
      print('Válido.');
    } else {
      erros.forEach((e) => print('- $e'));
    }
  }
}

