class EmailInvalido implements Exception {
  final String valor;
  const EmailInvalido(this.valor);

  @override
  String toString() => 'Email inválido: $valor';
}

final _regexEmail = RegExp(r'[\w.+-]+@[\w-]+\.[\w.-]+');

String validarEmail(String texto) {
  if (!_regexEmail.hasMatch(texto)) {
    throw EmailInvalido(texto);
  }
  return _regexEmail.firstMatch(texto)!.group(0)!;
}

void main() {
  const texto = 'Contato: ana@exemplo.com ou suporte@empresa.com.br\n'
      'Segunda linha do texto.\n'
      'Terceira linha, sem email aqui.';

  final linhas = texto.split('\n');
  final palavras = texto.split(RegExp(r'\s+'));
  final emails =
      _regexEmail.allMatches(texto).map((m) => m.group(0)!).toList();

  print('Linhas: ${linhas.length}');
  print('Palavras: ${palavras.length}');
  print('E-mails encontrados: $emails');

  for (final tentativa in ['contato@site.com', 'invalido-sem-arroba']) {
    try {
      final valido = validarEmail(tentativa);
      print('OK: $valido');
    } on EmailInvalido catch (e) {
      print('Falhou: $e');
    }
  }
}

DateTime parseDataBr(String data) {
  final partes = data.split('/');
  return DateTime(
    int.parse(partes[2]),
    int.parse(partes[1]),
    int.parse(partes[0]),
  );
}

String formatarDataBr(DateTime data) {
  final dd = data.day.toString().padLeft(2, '0');
  final mm = data.month.toString().padLeft(2, '0');
  return '$dd/$mm/${data.year}';
}

void main() {
  final hoje = DateTime(2026, 7, 22);
  final natal = DateTime(2026, 12, 25);
  final nascimento = parseDataBr('15/03/1998');

  final diasParaNatal = natal.difference(hoje).inDays;
  print('Hoje: ${formatarDataBr(hoje)}');
  print('Faltam $diasParaNatal dias para o Natal.');

  var idade = hoje.year - nascimento.year;
  final aniversarioJaPassou = (hoje.month > nascimento.month) ||
      (hoje.month == nascimento.month && hoje.day >= nascimento.day);
  if (!aniversarioJaPassou) idade--;

  print('Nascimento: ${formatarDataBr(nascimento)}');
  print('Idade: $idade anos');

  final prazo = hoje.add(const Duration(days: 30));
  print('Prazo de 30 dias a partir de hoje: ${formatarDataBr(prazo)}');
}

